def cap_rule(model, jj, y):
    te = list(model.te)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    interval = value(model.interval)
    return model.x[jj, y] <= model.x0[jj] + interval * sum(model.v[jj, yy] for yy in model.te if ordte[y] > ordte[yy])
model.cap = Constraint(model.j, model.t, rule=cap_rule)

def drql_rule(model, ss, y):
    te = list(model.te); sun = set(model.sun)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    interval = value(model.interval)
    expr = sum(model.lreq[ss, jj, y] * model.x[jj, y] for jj in model.j)
    if ss in sun:
        expr -= model.alr[y] * (model.ka[y] + interval * sum(model.ka[yy] for yy in model.te if ordte[y] > ordte[yy]))
    return expr == model.rql[ss, y]
model.drql = Constraint(model.s, model.t, rule=drql_rule)

def trql_rule(model, ss, y):
    te = list(model.te); sun = set(model.sun)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    LAST = 7; interval = value(model.interval)
    if ordte[y] <= LAST:
        return pyo.Constraint.Skip
    ym1 = te[ordte[y] - 2]
    expr = sum(model.lreq[ss, jj, y] * (model.x[jj, ym1] + interval * model.v[jj, ym1]) for jj in model.j)
    if ss in sun:
        expr -= interval * model.alr[y] * sum(model.ka[yp] for yp in model.te if ordte[y] > ordte[yp])
    return expr == model.rql[ss, y]
model.trql = Constraint(model.s, model.te, rule=trql_rule)

def ldsc_rule(model, ss, y):
    te = list(model.te); lset = list(model.lset)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    ordl = {ll: kk + 1 for kk, ll in enumerate(lset)}
    INITIAL = 1
    if ordte[y] <= INITIAL:
        return pyo.Constraint.Skip
    rhs = model.ls[y, ss]
    rhs += sum(model.ldg[ss, sp] * model.ld[sp, y] + model.lugt[ss, sp, y] * model.ul[sp, y] for sp in model.s)
    for yp in model.te:
        if not (ordte[y] >= ordte[yp]):
            continue
        for sp in model.s:
            for ll in lset:
                if (ordte[yp] + (ordl[ll] - 1)) > value(model.length[sp]):
                    coeff = value(model.sf['change', ss, ll, sp])
                    if coeff != 0:
                        tgt = ordte[yp] + (ordl[ll] - 1)
                        if 1 <= tgt <= len(te):
                            rhs += model.sf['change', ss, ll, sp] * model.ed[sp, te[tgt - 1]]
    for sp in model.s:
        for ll in lset:
            if (ordte[y] + (ordl[ll] - 1)) > value(model.length[sp]):
                coeff = value(model.sf['input', ss, ll, sp])
                if coeff != 0:
                    tgt = ordte[y] + (ordl[ll] - 1)
                    if 1 <= tgt <= len(te):
                        rhs += model.sf['input', ss, ll, sp] * model.ed[sp, te[tgt - 1]]
    return model.rql[ss, y] <= rhs
model.ldsc = Constraint(model.s, model.te, rule=ldsc_rule)

def exdef_rule(model, y):
    te = list(model.te)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    return model.pvv * model.ea[y] == sum(model.e[r, y] for r in model.im) + sum(model.em[yp] for yp in model.t if ordte[y] >= ordte[yp])
model.exdef = Constraint(model.t, rule=exdef_rule)

def fexch_rule(model, y):
    lhs = sum(model.apc[r, y] * model.con[y] + model.bk_agri[r, y] * model.ka[y]
              + sum(model.a[r, jj, y] * model.x[jj, y] + model.b[r, jj, y] * model.v[jj, y] for jj in model.j)
              for r in model.inc)
    return lhs == model.ea[y] + model.zt[y] + model.rgap[y]
model.fexch = Constraint(model.t, rule=fexch_rule)

def fgap_rule(model, y):
    te = list(model.te)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    return (model.rgap[y] - model.fc[y] - model.fdp[y] + model.infdp
            + model.pci * sum(model.fdp[yp] for yp in model.t if ordte[y] > ordte[yp]) == model.infc[y])
model.fgap = Constraint(model.t, rule=fgap_rule)

def ginv_rule(model, y):
    te = list(model.te)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    LAST = 7
    if ordte[y] > LAST:
        return pyo.Constraint.Skip
    return sum(model.k[jj, y] * model.v[jj, y] for jj in model.j) + model.ka[y] == model.inv[y]
model.ginv = Constraint(model.te, rule=ginv_rule)

def gsav_rule(model, y):
    return model.inv[y] == model.sav[y] + model.rgap[y]
model.gsav = Constraint(model.t, rule=gsav_rule)

def ggdp_rule(model, y):
    return model.con[y] + model.sav[y] == model.gdp[y]
model.ggdp = Constraint(model.t, rule=ggdp_rule)

def dsc_rule(model, y):
    te = list(model.te); tt = set(model.t)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    if y not in tt:
        return pyo.Constraint.Skip
    ym1 = te[ordte[y] - 2]
    return model.sav[y] - model.sav[ym1] <= model.mps * (model.gdp[y] - model.gdp[ym1])
model.dsc = Constraint(model.te, rule=dsc_rule)

def h_rule(model, y):
    te = list(model.te); tt = set(model.t)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    if y not in tt:
        return pyo.Constraint.Skip
    yp1 = te[ordte[y]]
    ym1 = te[ordte[y] - 2]
    return model.con[yp1] - model.con[y] == model.gamma * (model.con[y] - model.con[ym1])
model.h = Constraint(model.te, rule=h_rule)

def mb_rule(model, ii, y):
    te = list(model.te); tt = list(model.t)
    ordte = {yy: kk + 1 for kk, yy in enumerate(te)}
    expr = sum(model.a[ii, jj, y] * model.x[jj, y] + model.b[ii, jj, y] * model.v[jj, y] for jj in model.j)
    expr += model.bk_agri[ii, y] * model.ka[y] + model.apc[ii, y] * model.con[y] + model.apz[ii, y] * model.zt[y]
    expr += model.es[ii] * sum(model.zmi[y, yp] * model.em[yp] for yp in tt if ordte[y] >= ordte[yp])
    if ii in model.im:
        expr += model.e[ii, y]
    expr += model.csm[ii] * model.ea[y] + sum(model.ssr[ii, ss] * model.ul[ss, y] for ss in model.s)
    return expr <= 0
model.mb = Constraint(model.i, model.t, rule=mb_rule)
